/**
 * 象棋走子规则校验模块
 * 支持基本的棋子走法合法性判断
 */
// 通用校验：越界、原地不动、无棋子
function baseCheck(from, to, board) {
    if (from.x < 0 || from.x > 8 || from.y < 0 || from.y > 9 ||
        to.x < 0 || to.x > 8 || to.y < 0 || to.y > 9)
        return 'out-of-board';
    if (from.x === to.x && from.y === to.y)
        return 'same-pos';
    if (!board[from.x][from.y])
        return 'no-piece';
    return null;
}
// 通用校验：不能吃己方
function isSameSide(fromPiece, toPiece) {
    if (!toPiece)
        return false;
    return (fromPiece === fromPiece.toUpperCase()) === (toPiece === toPiece.toUpperCase());
}
function isValidMove(move) {
    const { from, to, board } = move;
    // 通用校验
    const err = baseCheck(from, to, board);
    if (err)
        return false;
    const fromPiece = board[from.x][from.y];
    const toPiece = board[to.x][to.y];
    if (isSameSide(fromPiece, toPiece))
        return false;
    switch (fromPiece.toUpperCase()) {
        case 'R': return canRookMove(from, to, board);
        case 'N': return canKnightMove(from, to, board);
        case 'B': return canElephantMove(from, to, board);
        case 'A': return canAdvisorMove(from, to, board);
        case 'K': return canKingMove(from, to, board);
        case 'C': return canCannonMove(from, to, board);
        case 'P': return canPawnMove(from, to, board);
        default: return false;
    }
}
// 车
function canRookMove(from, to, board) {
    if (from.x !== to.x && from.y !== to.y)
        return false;
    if (from.x === to.x) {
        const [min, max] = [from.y, to.y].sort((a, b) => a - b);
        for (let y = min + 1; y < max; y++) {
            if (board[from.x][y])
                return false;
        }
    }
    else {
        const [min, max] = [from.x, to.x].sort((a, b) => a - b);
        for (let x = min + 1; x < max; x++) {
            if (board[x][from.y])
                return false;
        }
    }
    return true;
}
// 马
function canKnightMove(from, to, board) {
    const dx = to.x - from.x, dy = to.y - from.y;
    if (!((Math.abs(dx) === 2 && Math.abs(dy) === 1) || (Math.abs(dx) === 1 && Math.abs(dy) === 2)))
        return false;
    if (Math.abs(dx) === 2) {
        if (board[from.x + dx / 2][from.y])
            return false;
    }
    else {
        if (board[from.x][from.y + dy / 2])
            return false;
    }
    return true;
}
// 相/象
function canElephantMove(from, to, board) {
    const dx = to.x - from.x, dy = to.y - from.y;
    if (Math.abs(dx) !== 2 || Math.abs(dy) !== 2)
        return false;
    const fromPiece = board[from.x][from.y];
    const isRed = fromPiece === fromPiece.toUpperCase();
    if ((isRed && to.y < 5) || (!isRed && to.y > 4))
        return false;
    if (board[from.x + dx / 2][from.y + dy / 2])
        return false;
    return true;
}
// 士/仕
function canAdvisorMove(from, to, board) {
    const dx = Math.abs(to.x - from.x), dy = Math.abs(to.y - from.y);
    if (dx !== 1 || dy !== 1)
        return false;
    const fromPiece = board[from.x][from.y];
    const isRed = fromPiece === fromPiece.toUpperCase();
    if (isRed) {
        return to.x >= 3 && to.x <= 5 && to.y >= 7 && to.y <= 9;
    }
    else {
        return to.x >= 3 && to.x <= 5 && to.y >= 0 && to.y <= 2;
    }
}
// 将/帅
function canKingMove(from, to, board) {
    const dx = Math.abs(to.x - from.x), dy = Math.abs(to.y - from.y);
    if (dx + dy !== 1)
        return false;
    const fromPiece = board[from.x][from.y];
    const isRed = fromPiece === fromPiece.toUpperCase();
    if (isRed) {
        if (!(to.x >= 3 && to.x <= 5 && to.y >= 7 && to.y <= 9))
            return false;
    }
    else {
        if (!(to.x >= 3 && to.x <= 5 && to.y >= 0 && to.y <= 2))
            return false;
    }
    return true;
}
// 炮
function canCannonMove(from, to, board) {
    if (from.x !== to.x && from.y !== to.y)
        return false;
    let count = 0;
    if (from.x === to.x) {
        const [min, max] = [from.y, to.y].sort((a, b) => a - b);
        for (let y = min + 1; y < max; y++) {
            if (board[from.x][y])
                count++;
        }
    }
    else {
        const [min, max] = [from.x, to.x].sort((a, b) => a - b);
        for (let x = min + 1; x < max; x++) {
            if (board[x][from.y])
                count++;
        }
    }
    const toPiece = board[to.x][to.y];
    if (!toPiece) {
        return count === 0;
    }
    else {
        const fromPiece = board[from.x][from.y];
        if (isSameSide(fromPiece, toPiece))
            return false;
        return count === 1;
    }
}
// 兵/卒
function canPawnMove(from, to, board) {
    const fromPiece = board[from.x][from.y];
    const isRed = fromPiece === fromPiece.toUpperCase();
    const dx = to.x - from.x, dy = to.y - from.y;
    if (Math.abs(dx) + Math.abs(dy) !== 1)
        return false;
    const crossedRiver = isRed ? from.y <= 4 : from.y >= 5;
    if (isRed) {
        if (!crossedRiver) {
            return dx === 0 && dy === -1;
        }
        else {
            return (dx === 0 && dy === -1) || (dy === 0 && Math.abs(dx) === 1);
        }
    }
    else {
        if (!crossedRiver) {
            return dx === 0 && dy === 1;
        }
        else {
            return (dx === 0 && dy === 1) || (dy === 0 && Math.abs(dx) === 1);
        }
    }
}

class BoardRender extends obsidian.MarkdownRenderChild {
    constructor(settings, containerEl, source) {
        super(containerEl);
        this.source = source;
        this.cellSize = 50; // 每个格子的大小
        this.fen = '';
        this.boardContainer = null;
        this.toolbarContainer = null;
        this.board = [];
        this.boardClickBound = false;
        this.pieces = [];
        this.hidenPieces = [];
        this.markedPiece = null;
        this.history = [];
        this.undoHistory = [];
        this.currentTurn = 'red'; // 新增，默认红方先手
        this.currentStep = 0;
        this.handleBoardClick = (e) => {
            if (!this.boardContainer)
                return;
            const boardRect = this.boardContainer.getBoundingClientRect();
            const mouseX = e.clientX - boardRect.left;
            const mouseY = e.clientY - boardRect.top;
            const gridX = Math.round(mouseX / this.cellSize) - 1;
            const gridY = Math.round(mouseY / this.cellSize) - 1;
            const clickedPiece = this.findPieceAt(gridX, gridY);
            if (!this.markedPiece) {
                // 没有标记棋子时，只能选中当前行棋方的棋子
                if (clickedPiece) {
                    const clickedIsRed = clickedPiece.type === clickedPiece.type.toUpperCase();
                    if ((this.currentTurn === 'red' && clickedIsRed) || (this.currentTurn === 'black' && !clickedIsRed)) {
                        this.markPiece(clickedPiece.pieceEl);
                        this.markedPiece = clickedPiece;
                    }
                }
                return;
            }
            // 有标记棋子时，尝试走子（无论目标是空还是有棋子）
            const moveValid = isValidMove({
                from: { x: this.markedPiece.x, y: this.markedPiece.y },
                to: { x: gridX, y: gridY },
                board: this.board,
            });
            if (moveValid) {
                // 检查是否与重做历史中的下一步一致
                const nextRedoMove = this.undoHistory[this.undoHistory.length - 1];
                const currentMove = {
                    fromX: this.markedPiece.x,
                    fromY: this.markedPiece.y,
                    toX: gridX,
                    toY: gridY
                };
                // 如果走的不是重做历史中的下一步，清空重做历史
                if (!nextRedoMove ||
                    nextRedoMove.fromX !== currentMove.fromX ||
                    nextRedoMove.fromY !== currentMove.fromY ||
                    nextRedoMove.toX !== currentMove.toX ||
                    nextRedoMove.toY !== currentMove.toY) {
                    this.undoHistory = [];
                }
                // 记录这一步
                this.history.push({
                    fromX: this.markedPiece.x,
                    fromY: this.markedPiece.y,
                    toX: gridX,
                    toY: gridY,
                    capture: clickedPiece ? clickedPiece : null,
                    Step: this.currentStep++
                });
                console.log(this.history);
                // 如果目标有棋子，隐藏目标棋子
                if (clickedPiece) {
                    clickedPiece.hidden = true;
                    clickedPiece.pieceEl?.setAttribute('display', 'none');
                    this.hidenPieces.push(clickedPiece);
                }
                // 移动棋子
                this.movePiece(this.markedPiece, gridX, gridY);
                this.currentTurn = this.currentTurn === 'red' ? 'black' : 'red';
                this.markedPiece = null; // 移动后取消标记
            }
            else {
                // 不能走，取消标记
                this.restorePiece(this.markedPiece.pieceEl);
                // 如果点击的是当前方棋子，重新标记
                if (clickedPiece) {
                    const clickedIsRed = clickedPiece.type === clickedPiece.type.toUpperCase();
                    if ((this.currentTurn === 'red' && clickedIsRed) || (this.currentTurn === 'black' && !clickedIsRed)) {
                        this.markPiece(clickedPiece.pieceEl);
                        this.markedPiece = clickedPiece;
                        return;
                    }
                }
                this.markedPiece = null;
            }
        };
        this.settings = settings;
        this.cellSize = settings.cellSize; // 从设置中获取 cellSize
    }
    // 主函数
    main() {
        this.parseSource();
        this.rend();
        this.bindEvents();
    }
    rend() {
        this.containerEl.empty();
        this.boardContainer = this.containerEl.createDiv({ cls: 'xiangqi-container' });
        // 插入棋盘棋子控件 SVG
        this.boardContainer.insertAdjacentHTML('afterbegin', generateBoardSvg(this.settings));
        const piecesContainer = this.boardContainer.querySelector('#xiangqi-pieces');
        if (piecesContainer) {
            piecesContainer.innerHTML = '';
            this.pieces.forEach((piece, index) => {
                const pieceHtml = createPieceSvg(piece.type, piece.x, piece.y, this.settings);
                piecesContainer.insertAdjacentHTML('beforeend', pieceHtml);
                const pieceEl = piecesContainer.lastElementChild;
                if (pieceEl) {
                    this.pieces[index].pieceEl = pieceEl;
                }
            });
        }
        const toolbar = this.boardContainer.querySelector('#toolbar');
        this.toolbarContainer = toolbar;
        if (toolbar) {
            toolbar.innerHTML = '';
            const buttonHtml = createButtonSvg(this.settings);
            toolbar.insertAdjacentHTML('beforeend', buttonHtml);
        }
    }
    bindEvents() {
        // 只绑定一次棋盘点击事件
        if (this.boardContainer && !this.boardClickBound) {
            this.boardContainer.addEventListener('click', this.handleBoardClick);
            this.boardClickBound = true;
        }
        const resetButton = this.toolbarContainer.querySelector('#reset');
        if (resetButton) {
            resetButton.addEventListener('click', () => {
                this.onunload(); // 卸载当前棋盘
                this.history = []; // 清空历史
                this.undoHistory = []; // 清空撤销历史
                this.main(); // 重新渲染
            });
            this.markedPiece = null; // 重置标记棋子
            this.currentTurn = this.source.includes('w') ? 'red' : 'black'; // 重置当前回合
        }
        const undoButton = this.toolbarContainer.querySelector('#undo');
        if (undoButton) {
            undoButton.addEventListener('click', () => {
                console.log(this.history);
                this.undoMove(); // 撤销上一步 
            });
        }
        const redoButton = this.toolbarContainer.querySelector('#redo');
        if (redoButton) {
            redoButton.addEventListener('click', () => {
                this.redoMove();
            });
        }
    }
    // 解析相关私有方法
    parseSource() {
        const board = Array.from({ length: 10 }, () => Array(9).fill(null));
        const pieces = [];
        const [position, turn] = this.source.trim().split(/\s+/);
        if (!position)
            return { board, pieces };
        const rows = position.split('/');
        if (rows.length !== 10)
            return { board, pieces };
        rows.forEach((row, y) => {
            let x = 0;
            for (const char of row) {
                if (/[1-9]/.test(char)) {
                    x += parseInt(char);
                }
                else if (/[a-zA-Z]/.test(char)) {
                    board[x][y] = char;
                    pieces.push({ type: char, x, y });
                    x++;
                }
            }
        });
        this.board = board;
        this.pieces = pieces;
        // 根据 FEN 初始化 currentTurn
        this.currentTurn = turn === 'b' ? 'black' : 'red';
    }
    markPiece(pieceEl) {
        if (!pieceEl.hasAttribute('data-original-transform')) {
            const originalTransform = pieceEl.getAttribute('transform') || '';
            const cleanTransform = originalTransform.replace(/\s*scale\([^)]+\)/, '');
            pieceEl.setAttribute('data-original-transform', cleanTransform);
            pieceEl.setAttribute('transform', `${cleanTransform} scale(1.2)`);
        }
    }
    restorePiece(pieceEl) {
        const originalTransform = pieceEl.getAttribute('data-original-transform');
        if (originalTransform !== null) {
            pieceEl.setAttribute('transform', originalTransform);
            pieceEl.removeAttribute('data-original-transform');
        }
    }
    findPieceAt(x, y) {
        return this.pieces.find(p => p.x === x && p.y === y && !p.hidden);
    }
    movePiece(movingPiece, toX, toY) {
        const fromX = movingPiece.x;
        const fromY = movingPiece.y;
        this.board[fromX][fromY] = null;
        this.board[toX][toY] = movingPiece.type;
        this.restorePiece(movingPiece.pieceEl);
        movingPiece.x = toX;
        movingPiece.y = toY;
        movingPiece.pieceEl.setAttribute('transform', `translate(${(toX + 1) * this.cellSize},${(toY + 1) * this.cellSize})`);
        movingPiece.pieceEl.setAttribute('data-x', String(toX));
        movingPiece.pieceEl.setAttribute('data-y', String(toY));
    }
    undoMove() {
        if (this.history.length === 0)
            return;
        const lastMove = this.history.pop();
        // 将悔棋步骤存入悔棋历史
        this.undoHistory.push(lastMove);
        const { fromX, fromY, toX, toY, capture, Step } = lastMove;
        // 找到需要回退的棋子
        const returnPiece = this.findPieceAt(toX, toY);
        if (!returnPiece)
            return;
        // 更新棋盘状态，注意坐标顺序是 [x][y]
        this.board[toX][toY] = null;
        this.board[fromX][fromY] = returnPiece.type;
        // 更新棋子位置
        returnPiece.x = fromX;
        returnPiece.y = fromY;
        returnPiece.pieceEl?.setAttribute('transform', `translate(${(fromX + 1) * this.cellSize},${(fromY + 1) * this.cellSize})`);
        returnPiece.pieceEl?.setAttribute('data-x', String(fromX));
        returnPiece.pieceEl?.setAttribute('data-y', String(fromY));
        // 恢复被吃掉的棋子
        if (capture) {
            capture.hidden = false;
            capture.pieceEl?.removeAttribute('display');
            this.hidenPieces = this.hidenPieces.filter(p => p !== capture);
            this.board[toX][toY] = capture.type;
        }
        this.currentStep--;
        this.currentTurn = this.currentTurn === 'red' ? 'black' : 'red';
    }
    redoMove() {
        if (this.undoHistory.length === 0)
            return;
        const moveToRedo = this.undoHistory.pop();
        const { fromX, fromY, toX, toY, capture } = moveToRedo;
        // 找到要移动的棋子
        const movingPiece = this.findPieceAt(fromX, fromY);
        if (!movingPiece)
            return;
        // 如果目标位置有棋子,需要隐藏它
        if (capture) {
            capture.hidden = true;
            capture.pieceEl?.setAttribute('display', 'none');
            this.hidenPieces.push(capture);
        }
        // 移动棋子
        this.movePiece(movingPiece, toX, toY);
        // 记录到历史中
        this.history.push(moveToRedo);
        // 切换回合
        this.currentTurn = this.currentTurn === 'red' ? 'black' : 'red';
        this.currentStep++;
    }
    // 卸载相关方法
    onunload() {
        // 清理棋盘事件
        if (this.boardContainer && this.boardClickBound) {
            this.boardContainer.removeEventListener('click', this.handleBoardClick);
            this.boardClickBound = false;
        }
        // 确保卸载时重置当前标记的棋子
        this.markedPiece = null;
    }
}

const THEME_STYLES = ["light", "dark"];
const DEFAULT_SETTINGS = {
    theme: 'light',
    cellSize: 50
};
class settingTab extends obsidian.PluginSettingTab {
    constructor(app, plugin) {
        super(app, plugin);
        this.plugin = plugin;
    }
    display() {
        let { containerEl } = this;
        containerEl.empty();
        containerEl.createEl("h2", { text: "Obsidian 中国象棋设置" });
        new obsidian.Setting(containerEl)
            .setName("主题")
            .setDesc("设置棋盘主题.")
            .addDropdown((dropdown) => {
            let styles = {};
            THEME_STYLES.map((style) => (styles[style] = style));
            dropdown.addOptions(styles);
            dropdown.setValue(this.plugin.settings.theme).onChange((theme) => {
                this.plugin.settings.theme = theme;
                this.plugin.saveSettings();
            });
        });
        new obsidian.Setting(containerEl)
            .setName("界面大小")
            .setDesc("调整界面大小（单位：px）")
            .addSlider((slider) => {
            slider
                .setLimits(20, 60, 1) // 最小值 30 最大值 60，步长 5
                .setValue(this.plugin.settings.cellSize) // 默认值
                .onChange(async (value) => {
                this.plugin.settings.cellSize = value;
                await this.plugin.saveSettings(); // 保存设置
                // this.applyCellsize(value); // 应用新字体大小
            });
            // 可选：在滑块旁边显示当前值
            slider.sliderEl.createSpan({
                text: ` ${this.plugin.settings.cellSize}px`,
                cls: "slider-value",
            });
            // 实时更新显示值
            slider.sliderEl.oninput = (evt) => {
                const value = evt.target.value;
                const displayEl = slider.sliderEl.nextSibling;
                if (displayEl)
                    displayEl.textContent = ` ${value}px`;
            };
        });
    }
}

class XiangqiPlugin extends obsidian.Plugin {
    async onload() {
        await this.loadSettings();
        this.addSettingTab(new settingTab(this.app, this));
        this.registerMarkdownCodeBlockProcessor('xiangqi', (source, el) => {
            new BoardRender(this.settings, el, source).main();
        });
    }
    async loadSettings() {
        this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
    }
    async saveSettings() {
        await this.saveData(this.settings);
    }
}

module.exports = XiangqiPlugin;
